import java.util.Scanner;
public class EX04150803 {
    // 声明函数式接口
    @FunctionalInterface
    interface StringNumberHandler {
        Number handle(String str_num);
    }
    // 静态方法，用于处理数字字符串
    public static void printNumber(StringNumberHandler num, String s) {
        num.handle(s);
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("请输入一个实数数字串:");
        String input = scanner.nextLine();

        // 使用成员内部类 IntegerHandler 实现函数式接口，取整数部分
        class IntegerHandler implements StringNumberHandler {
            @Override
            public Number handle(String str_num) {
                int intValue = (int) Double.parseDouble(str_num);
                System.out.println("Number:" + intValue);
                return intValue;
            }
        }
        printNumber(new IntegerHandler(), input);

        // 使用成员内部类 DoubleHandler 实现函数式接口，四舍五入保留两位小数
        class DoubleHandler implements StringNumberHandler {
            @Override
            public Number handle(String str_num) {
                double doubleValue = Double.parseDouble(str_num);
                doubleValue = Math.round(doubleValue * 100) / 100.0;
                System.out.println("Number:" + doubleValue);
                return doubleValue;
            }
        }
        printNumber(new DoubleHandler(), input);

        // 使用成员局部内部类实现函数式接口，取整数部分
        {
            class LocalIntegerHandler implements StringNumberHandler {
                @Override
                public Number handle(String str_num) {
                    int intValue = (int) Double.parseDouble(str_num);
                    System.out.println("Number:" + intValue);
                    return intValue;
                }
            }
            printNumber(new LocalIntegerHandler(), input);
        }

        // 使用成员局部内部类实现函数式接口，四舍五入保留两位小数
        {
            class LocalDoubleHandler implements StringNumberHandler {
                @Override
                public Number handle(String str_num) {
                    double doubleValue = Double.parseDouble(str_num);
                    doubleValue = Math.round(doubleValue * 100) / 100.0;
                    System.out.println("Number:" + doubleValue);
                    return doubleValue;
                }
            }
            printNumber(new LocalDoubleHandler(), input);
        }

        // 使用匿名内部类实现函数式接口，取整数部分
        printNumber(new StringNumberHandler() {
            @Override
            public Number handle(String str_num) {
                int intValue = (int) Double.parseDouble(str_num);
                System.out.println("Number:" + intValue);
                return intValue;
            }
        }, input);

        // 使用匿名内部类实现函数式接口，四舍五入保留两位小数
        printNumber(new StringNumberHandler() {
            @Override
            public Number handle(String str_num) {
                double doubleValue = Double.parseDouble(str_num);
                doubleValue = Math.round(doubleValue * 100) / 100.0;
                System.out.println("Number:" + doubleValue);
                return doubleValue;
            }
        }, input);

        // 使用lambda表达式，取整数部分
        printNumber((str_num) -> {
            int intValue = (int) Double.parseDouble(str_num);
            System.out.println("Number:" + intValue);
            return intValue;
        }, input);

        // 使用lambda表达式，四舍五入保留两位小数
        printNumber((str_num) -> {
            double doubleValue = Double.parseDouble(str_num);
            doubleValue = Math.round(doubleValue * 100) / 100.0;
            System.out.println("Number:" + doubleValue);
            return doubleValue;
        }, input);
    }
}
