import java.util.Arrays;
@FunctionalInterface
interface FilterNumber {
    Number[] handle(Number[] nums);
}

public class EX04150804 {
    public static Number[] filterNums(FilterNumber f, Number[] nums) {
        return f.handle(nums);
    }

    public static void main(String[] args) {
        // 处理整数数组
        Number[] intArray = {2, 3, 5, 6, 8, 10, 13, 18};
        Number[] resultInt = filterNums((nums) -> {
            int count = 0;
            for (Number num : nums) {
                if (num.intValue() % 2 == 0) {
                    count++;
                }
            }
            Number[] result = new Number[count];
            int index = 0;
            for (Number num : nums) {
                if (num.intValue() % 2 == 0) {
                    result[index++] = num;
                }
            }
            return result;
        }, intArray);
        System.out.println("过滤掉数组中的奇数后,数组中的数是:");
        for (Number num : resultInt) {
            System.out.print(num + " ");
        }
        System.out.println();

        // 处理Double型数组
        Number[] doubleArray = {57.6, 65.5, 54.5, 59.5, 86.6, 79.3, 35.5};
        Number[] resultDouble = filterNums((nums) -> {
            int count = 0;
            for (Number num : nums) {
                if (num.doubleValue() >= 60) {
                    count++;
                }
            }
            Number[] result = new Number[count];
            int index = 0;
            for (Number num : nums) {
                if (num.doubleValue() >= 60) {
                    result[index++] = num;
                }
            }
            return result;
        }, doubleArray);
        System.out.println("过滤掉小于60的数后,数组中的数是:");
        for (Number num : resultDouble) {
            System.out.print(num + " ");
        }
    }
}
