class Student {
    private String stuID;
    private String name;
    private int ChineseScore;
    private int MathScore;
    private int EnglishScore;
    // 无参构造方法
    public Student() {
    }
    // 有两个参数的构造方法
    public Student(String stuID, String name) {
        this.stuID = stuID;
        this.name = name;
    }
    // 带所有参数的构造方法
    public Student(String stuID, String name, int ChineseScore, int MathScore, int EnglishScore) {
        this.stuID = stuID;
        this.name = name;
        this.ChineseScore = ChineseScore;
        this.MathScore = MathScore;
        this.EnglishScore = EnglishScore;
    }
    // get和set方法
    public String getStuID() {
        return stuID;
    }
    public void setStuID(String stuID) {
        this.stuID = stuID;
    }
    public String getName() {
        return name;
    }
    public void setName(String name) {
        this.name = name;
}

    public int getChineseScore() {
        return ChineseScore;
    }
    public void setChineseScore(int ChineseScore) {
        this.ChineseScore = ChineseScore;
    }
    public int getMathScore() {
        return MathScore;
    }
    public void setMathScore(int MathScore) {
        this.MathScore = MathScore;
    }
    public int getEnglishScore() {
        return EnglishScore;
    }
    public void setEnglishScore(int EnglishScore) {
        this.EnglishScore = EnglishScore;
    }
    @Override
    public String toString() {
        return "学号=" + stuID + ", 姓名=" + name + "\n 语文成绩=" + ChineseScore + ", 数学成绩=" + MathScore + ", 英语成绩=" + EnglishScore;
    }
}
